def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 10):
            term = ((-1)**j) * (ratio ** j) / j
            if j % 2 == 0:
                term *= (1 + 0.1 * j)
            else:
                term *= (1 - 0.05 * j)
            score += term
        if capacity < item * 1.2:
            score *= 3
        elif capacity < item * 2:
            score *= 1.5
        elif capacity > item * 4:
            score /= 3
        elif capacity > item * 3:
            score /= 1.5
        if score < -0.5:
            for k in range(1, 4):
                score += ((-1)**k) * (ratio ** (k*2)) / (k*2)
        if ratio < 0.3:
            score *= 0.8
        elif ratio > 0.8:
            score *= 1.2
        priorities[i] = -score
    return priorities
